                case .userCancel, .systemCancel, .appCancel:
                    completion(.cancelled)
                case .userFallback:
                    completion(.fallback)
                case .biometryLockout:
                    completion(.failed("Biometrics are locked. Please use your password and try again later."))
                case .biometryNotEnrolled:
                    completion(.unavailable("No biometrics are enrolled. Please set up Face ID/Touch ID in Settings."))
                case .biometryNotAvailable:
                    completion(.unavailable("Biometric authentication is not available on this device."))
                case .authenticationFailed:
                    completion(.failed("Authentication failed. Please try again."))
                default:
                    completion(.failed(laError?.localizedDescription ?? "Authentication failed. Please try again."))
                }
